 94→function buildApplicationRecord(
 95→  job: ScanResult | { title: string; company: string; url: string; match_score: number; source?: string },
 96→  resumeVariant: string,
 97→  location: string = "Remote"
 98→): ApplicationRecord {
 99→  const id = `app-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
100→  const now = new Date().toISOString();
101→  const dedupHash = computeDedupHash(
102→    job.company,
103→    job.title,
104→    location
105→  );
106→
107→  return {
108→    id,
109→    timestamp: now,
110→    company: job.company,
111→    title: job.title,
112→    url: job.url,
113→    workflow: "auto-apply",
114→    match_score: job.match_score,
115→    resume_variant: resumeVariant,
116→    cover_letter: false, // Auto-apply never includes cover letter
117→    status: "submitted",
118→    dedup_hash: dedupHash,
119→    referral_status: "none",
120→    outcome: null,
121→    callback_date: null,
122→    notes: "",
123→    updated_at: now,
124→  };
125→}
